  "verses": [
    {
      "n": 26,
      "column": "left",
      "text": "Wiꞥſch fuhtija Mohsu\nfawu Kalpu/ un Aäronu/ ko\nwiꞥſch bij iswehlejs.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Tee darrija winnu Star-\npâ winna Brihnumus/ un\nBrihnuma-Sihmes eekſch tahs\nSenunes Kam.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Wiꞥſch fuhtija Tumsibu/\ntad tumsch ktua/ un tee turre-\njahs winna Wahrdam pretti.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Wiꞥſch pawehrtija win-\nnu Uhdeni par Aſtinim/ un no-\nkawe winna Siwis.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Winnu Semme ismu-\ndschinaja Wardes/ winnu Keh-\nnigu Kambardês.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Wiꞥſch runnaja/ tad nah-\nze Kukkaizi/ Uttis wiſſâs win-\nnu Rohbeschâs.\n"
    },
    {
      "n": 32,
      "column": "left",
      "text": "Wiꞥſch dewe teem Kruf-\nfu Leetus Weeta/ leefmainu\nUgguni winnu Semmê.\n"
    },
    {
      "n": 33,
      "column": "left",
      "text": "Un kawe winnu Wihna-\nKohkus/ un winnu Wihges-\nKohkus/ un falaustija winnu\nRohbeschû Kohkus.\n"
    },
    {
      "n": 34,
      "column": "left",
      "text": "Wiꞥſch fazzija/ tad nah-\nje tee Giſſeni/nn Wabboles ne-is-\nſaitama Pulka.\n"
    },
    {
      "n": 35,
      "column": "left",
      "text": "Kas wiſſu Sahli winnu\nSemmes apehde/ ir winnu\nSemmes Augtus norihje.\n"
    },
    {
      "n": 36,
      "column": "left",
      "text": "Wiꞥſch kawe arri wiſſus\nPirmdſimmuschus winnu Sem-\nmê/ un wiſſu teinnu pirino\nStiprumu.\n"
    },
    {
      "n": 37,
      "column": "left",
      "text": "Un iswedde tohs ar Su-\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Egiptes-Semmê preeza-\njahs/ kad tee isgahje/ jo winnu\nBihjaschana bija pahr teem krit-\ntuſi.\n"
    },
    {
      "n": 39,
      "column": "right",
      "text": "Wiꞥſch isplatttija weenu\nPadebbefi par Apteggû/ un ug-\nguni Nakti par Apgaitmo-\nschann.\n"
    },
    {
      "n": 40,
      "column": "right",
      "text": "Tee suhdse/ un wiꞥſch lie-\nke Paipales nahkt/ un pa-ehdi-\nnaja tohs ar Debbes Maisi.\n"
    },
    {
      "n": 41,
      "column": "right",
      "text": "Wiꞥſch pahrschkehle wee-\nnu Akmina-Kalnu/ tad istezzeja\nUhdens/ ka Uppes skrebje eekſch\ntukſchahm Weetahm.\n"
    },
    {
      "n": 42,
      "column": "right",
      "text": "Jo wiꞥſch atminnejahs\ntawa fwehta Wahrdâ/ pee Ah-\nbrâina fawa Kalpa.\n"
    },
    {
      "n": 43,
      "column": "right",
      "text": "Ta iswedde wiꞥſch fa-\nwus Landis ar Preeku/ un fa-\nwus Iswehletus ar Gawile-\nschanu.\n"
    },
    {
      "n": 44,
      "column": "right",
      "text": "Un dewe teemi to Paga-\nnu Semmes/ ka tee eemantoja\nto Laischu geuhtu Darbu.\n"
    },
    {
      "n": 45,
      "column": "right",
      "text": "Ka teem bij winna Liffku-\nmus turreht/ un winna Bautli-\nbas fargaht/ Alleluja.\n"
    },
    {
      "n": �,
      "column": "right",
      "text": "Ta CVI. Dseefma.\nWeena Pateikſchanas-Dseefma/ kas pirmak\ntohs leelakus Grehkus/ ar ko tee Judu Lau-\ndis daschadas Sohdibas novelniiſchi/ isteiz:\n6. Kur tomehr Deews allach Schehlastibu\nvn Girds-Schehlastibu parahdijs: 8/etc.\n1. Alleluja: Pateizeet tam\nKURGAM/ jo wiꞥſch\nVier labs/ jo winna Scheh-\nlastiva paleek muhschigi.\n2. Kas\n"
    }
  ],
